import LocalAuthentication
import UIKit

class AuthenticationManager {
    static let shared = AuthenticationManager()
    private init() {}
    
    private let userDefaults = UserDefaults.standard
    private let authContext = LAContext()
    private let authReason = "Authenticate to access your account"
    
    func authenticateUser(completion: @escaping (Bool, Error?) -> Void) {
        var error: NSError?
        
        guard LAContext().canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error)
            return
        }
        
        let policy = LAContext().biometryType == .faceID ? .deviceOwnerAuthenticationWithBiometrics : .deviceOwnerAuthenticationWithBiometrics
        
        authContext.evaluatePolicy(
            policy,
            localizedReason: authReason,
            reply: { [weak self] success, error in
                DispatchQueue.main.async {
                    if success {
                        self?.setUserAuthenticated()
                        completion(true, nil)
                    } else {
                        completion(false, error)
                    }
                }
            }
        )
    }
    
    func authenticateWithPassword(completion: @escaping (Bool, Error?) -> Void) {
        authContext.evaluatePolicy(
            .deviceOwnerAuthentication,
            localizedReason: authReason,
            reply: { success, error in
                DispatchQueue.main.async {
                    if success {
                        self.setUserAuthenticated()
                        completion(true, nil)
                    } else {
                        completion(false, error)
                    }
                }
            }
        )
    }
    
    func setUserAuthenticated() {
        userDefaults.set(true, forKey: "isUserAuthenticated")
        userDefaults.synchronize()
    }
    
    func isUserAuthenticated() -> Bool {
        return userDefaults.bool(forKey: "isUserAuthenticated")
    }
    
    func clearAuthentication() {
        userDefaults.removeObject(forKey: "isUserAuthenticated")
        userDefaults.synchronize()
    }
    
    func showAuthenticationAlert(
        in viewController: UIViewController,
        completion: @escaping (Bool) -> Void
    ) {
        let alert = UIAlertController(
            title: "Authentication Required",
            message: "Please authenticate to access your account",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Use Face ID", style: .default) { _ in
            self.authenticateUser { success, _ in
                if success {
                    completion(true)
                } else {
                    self.showAuthenticationAlert(in: viewController, completion: completion)
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Enter Password", style: .default) { _ in
            self.authenticateWithPassword { success, _ in
                if success {
                    completion(true)
                } else {
                    self.showAuthenticationAlert(in: viewController, completion: completion)
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completion(false)
        })
        
        viewController.present(alert, animated: true)
    }
}

class LoginViewController: UIViewController {
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Login"
        
        let loginButton = UIButton(type: .system)
        loginButton.setTitle("Login", for: .normal)
        loginButton.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .medium)
        loginButton.backgroundColor = .systemBlue
        loginButton.setTitleColor(.white, for: .normal)
        loginButton.layer.cornerRadius = 8
        loginButton.addTarget(self, action: #selector(loginButtonTapped), for: .touchUpInside)
        
        view.addSubview(loginButton)
        loginButton.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            loginButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            loginButton.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            loginButton.widthAnchor.constraint(equalToConstant: 120),
            loginButton.heightAnchor.constraint(equalToConstant: 44)
        ])
    }
    
    @objc private func loginButtonTapped() {
        AuthenticationManager.shared.showAuthenticationAlert(in: self) { success in
            if success {
                self.navigateToMainApp()
            }
        }
    }
    
    private func navigateToMainApp() {
        let mainViewController = MainViewController()
        let navigationController = UINavigationController(rootViewController: mainViewController)
        (UIApplication.shared.connectedScenes.first?.delegate as? SceneDelegate)?.window?.rootViewController = navigationController
    }
}

